CREATE TRIGGER [Global].[Equipment_History]ON [Global].[Equipment]AFTER INSERT, UPDATE, DELETE ASDECLARE @HistoryAction CHAR(1)set @HistoryAction = (SELECT TOP 1 	CASE 		WHEN i.EquipmentId IS NOT NULL AND d.EquipmentId IS NULL THEN 'I' 		WHEN i.EquipmentId IS NOT NULL AND d.EquipmentId IS NOT NULL THEN 'U' 		WHEN i.EquipmentId IS NULL AND d.EquipmentId IS NOT NULL THEN 'D'		ELSE 'NA'	END AS HistoryActionfrom inserted as i	full outer join deleted as d on i.EquipmentId = d.EquipmentId)IF @HistoryAction = 'I' OR @HistoryAction = 'U'BEGIN	INSERT INTO History.Global_Equipment([EquipmentId], [LineId], [ProcessId], [Name], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [EquipmentId], [LineId], [ProcessId], [Name], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction 	FROM insertedENDELSE IF @HistoryAction = 'D'BEGIN	INSERT INTO History.Global_Equipment([EquipmentId], [LineId], [ProcessId], [Name], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [EquipmentId], [LineId], [ProcessId], [Name], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction  	FROM deletedEND